		else if (ex3_pipedown)
			fdsu_yy_rslt_denorm <= ex3_rslt_denorm;
		else
			fdsu_yy_rslt_denorm <= fdsu_yy_rslt_denorm;
	always @(posedge ex2_pipe_clk)
		if (ex2_pipedown) begin
