		.module_en(cp0_fpu_icg_en),
		.pad_yy_icg_scan_en(pad_yy_icg_scan_en)
	);
	assign expnt_rst_clk_en = ((ex1_save_op0_gate || ex1_pipedown_gate) || ex2_pipedown) || ex3_pipedown;
