	assign ex2_expnt_adder_op0[9:0] = fdsu_expnt_rst[9:0];
	assign fdsu_yy_result_inf = fdsu_result_inf;
	assign fdsu_yy_result_lfn = fdsu_result_lfn;
	assign fdsu_yy_of = fdsu_of;
	assign fdsu_yy_uf = fdsu_uf;
