		endcase
	assign ex1_sqrt_op0_expnt_0 = (ex1_op0_id_nor ? ex1_oper_id_expnt[0] : ex1_div_op0_expnt[0]);
	assign ex1_sqrt_expnt_odd = !ex1_sqrt_op0_expnt_0;
